        ikInput.className = "saip-wizard-text saip-wizard-text--mono";
        ikInput.maxLength = 32;
        ikInput.value = ik;
        _saipWizardRow(host, "IK (16 B)", ikInput,
          "Integrity Key derived from the AKA run.");

