  var _SAIP_WIZARD_KEYS = _saipKeysWizard("KEYS",
    "3GPP TS 31.102 §4.2.4 — KSI + CK + IK (CS domain).");
  var _SAIP_WIZARD_KEYSPS = _saipKeysWizard("KEYSPS",
    "3GPP TS 31.102 §4.2.27 — KSI + CK + IK (PS domain).");

  // 3GPP TS 31.102 §4.2.36 — START / HFN.
