      _saipWizardRow(host, "Address type", sel, "Per TS 31.103 §4.2.8.");

      var valueInput = document.createElement("input");
      valueInput.type = "text";
      valueInput.className = "saip-wizard-text saip-wizard-text--wide";
      valueInput.value = initialValue;
