      input.spellcheck = false;
      input.value = saipFormatHexPretty(_saipBytesToHex(bytes));
      _saipWizardRow(host, "CCP1 record hex", input,
        "TLV payload, exactly " + recordSize + " bytes.");

      var preview = document.createElement("code");
