  // 3GPP TS 31.102 §4.2.9b — EF.KC / EF.KCGPRS (9 B):
  // 8-byte ciphering key + 1-byte CKSN.
  function _saipKcWizard(label, spec) {
    return {
      title: "EF." + label + " wizard",
      spec: spec,
      render: function (host, currentHex, applyFn) {
        var bytes = _saipHexToBytes(currentHex);
        while (bytes.length < 9) bytes.push(0x00);
        var keyHex = _saipBytesToHex(bytes.slice(0, 8));
        var cksn = bytes[8] & 0xFF;

        var keyInput = document.createElement("input");
        keyInput.type = "text";
        keyInput.className = "saip-wizard-text saip-wizard-text--mono";
        keyInput.maxLength = 16;
        keyInput.value = keyHex;
        _saipWizardRow(host, "Kc key (8 B)", keyInput,
          "16 hex chars; GSM ciphering key.");

        var cksnInput = document.createElement("input");
        cksnInput.type = "number";
        cksnInput.className = "saip-wizard-text";
        cksnInput.min = "0";
        cksnInput.max = "7";
        cksnInput.value = String(cksn & 0x07);
        _saipWizardRow(host, "CKSN", cksnInput, "0..7 (7 means no valid key).");

        _saipWizardApplyButton(host, "Apply " + label, function () {
          var kb = _saipHexToBytes(keyInput.value);
          if (kb.length !== 8) {
            throw new Error("Kc key must be exactly 8 bytes.");
          }
          var c = parseInt(cksnInput.value, 10);
          if (!Number.isFinite(c) || c < 0 || c > 7) {
            throw new Error("CKSN must be 0..7.");
          }
          return { hex: _saipBytesToHex(kb.concat([c & 0x07])) };
        }, applyFn);
      },
    };
  }

