  // 3GPP TS 31.102 §4.4.2.4 — EF.EXT (extension records). Used by
  // EF.EXT1, EF.EXT2, etc. Records are 13 B:
  //   byte 1   : record type (0x00=no record, 0x01=Calling Party
  //              Subaddress, 0x02=Additional data, 0x03=CCP)
  //   byte 2   : length of contents in bytes 3..12 (0..10)
  //   bytes 3-12: extension data (TS 31.102 §4.4.2.4)
  //   byte 13  : next-record id (0xFF = end of chain)
  var _SAIP_RECORD_WIZARD_EXT = {
    title: "EF.EXT wizard",
    spec: "3GPP TS 31.102 §4.4.2.4 — Extension chain record (13 B).",
    render: function (host, recordHex, recordSize, applyFn) {
      if (recordSize !== 13) {
        throw new Error("EF.EXT records are 13 B (got " + recordSize + ").");
      }
      var bytes = _saipHexToBytes(recordHex);
      while (bytes.length < 13) bytes.push(0xFF);
      var typeInit = bytes[0] & 0xFF;
      var lenInit = bytes[1] & 0xFF;
      var dataInit = _saipBytesToHex(bytes.slice(2, 12));
      var nextInit = bytes[12] & 0xFF;

      var typeSel = document.createElement("select");
      typeSel.className = "saip-wizard-text";
      [
        { v: 0x00, l: "0 — End of chain" },
        { v: 0x01, l: "1 — Calling Party Subaddress" },
        { v: 0x02, l: "2 — Additional data" },
        { v: 0x03, l: "3 — Capability/Configuration Parameters" },
      ].forEach(function (opt) {
        var o = document.createElement("option");
        o.value = String(opt.v);
        o.textContent = opt.l;
        if (opt.v === typeInit) o.selected = true;
        typeSel.appendChild(o);
      });
      _saipWizardRow(host, "Record type", typeSel, "Per TS 31.102 §4.4.2.4.");

      var lenInput = document.createElement("input");
      lenInput.type = "number";
      lenInput.className = "saip-wizard-text";
      lenInput.min = "0";
      lenInput.max = "10";
      lenInput.value = String(Math.min(lenInit, 10));
      _saipWizardRow(host, "Length (0..10)", lenInput,
        "Number of meaningful bytes in the extension data.");

      var dataInput = document.createElement("input");
      dataInput.type = "text";
      dataInput.className = "saip-wizard-text saip-wizard-text--mono";
      dataInput.maxLength = 20;
      dataInput.value = dataInit;
      _saipWizardRow(host, "Extension data (10 B hex)", dataInput,
        "FF-padded — only the first 'length' bytes are meaningful.");

      var nextInput = document.createElement("input");
      nextInput.type = "text";
      nextInput.className = "saip-wizard-text saip-wizard-text--mono";
      nextInput.maxLength = 2;
      nextInput.value = _saipHexPad2(nextInit);
      _saipWizardRow(host, "Next record id", nextInput,
        "FF = end of chain.");

      _saipWizardApplyButton(host, "Apply EXT", function () {
        var t = parseInt(typeSel.value, 10);
        var l = parseInt(lenInput.value, 10);
        if (!Number.isFinite(l) || l < 0 || l > 10) {
          throw new Error("Length must be 0..10.");
        }
        var d = _saipHexToBytes(dataInput.value);
        while (d.length < 10) d.push(0xFF);
        if (d.length > 10) d = d.slice(0, 10);
        var nx = parseInt(nextInput.value, 16);
        if (!Number.isFinite(nx) || nx < 0 || nx > 0xFF) {
          throw new Error("Next id must be a hex byte.");
        }
        return { hex: _saipBytesToHex([t & 0xFF, l & 0xFF].concat(d).concat([nx])) };
      }, applyFn);
    },
  };

